PREFIX matsci: <https://cwrusdle.bitbucket.io/matsci/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?sample ?materialClass ?label
WHERE {
  ?sample a matsci:MaterialSample .
  ?sample a ?materialClass .
  ?materialClass rdfs:subClassOf* matsci:MaterialClass .
  OPTIONAL { ?materialClass rdfs:label ?label }
}

PREFIX matsci: <https://cwrusdle.bitbucket.io/matsci/>
PREFIX cco: <https://www.commoncoreontologies.org/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?specimen ?identifier ?agent ?label
WHERE {
  ?specimen a matsci:Specimen .
  ?specimen cco:ont00001879 ?identifier .
  ?identifier a matsci:Identifier .
  OPTIONAL { ?identifier cco:ont00001803 ?agent .
             ?agent a matsci:Agent }
  OPTIONAL { ?identifier rdfs:label ?label }
}

PREFIX matsci: <https://cwrusdle.bitbucket.io/matsci/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?state ?label
WHERE {
  VALUES ?sample { <http://example.org/resource#sample.001> }
  ?sample a matsci:MaterialSample .
  ?state a matsci:PhysicalState ;
         obo:BFO_0000197 ?sample .
  OPTIONAL { ?state rdfs:label ?label }
}

