  ?specimen a matsci:Specimen .
  ?specimen cco:ont00001879 ?composition .
  ?composition a matsci:ChemicalComposition ;
               obo:BFO_0000051 ?constituent .
  ?constituent a matsci:Constituent .
  OPTIONAL { ?constituent cco:ont00001769 ?fraction }
  OPTIONAL { ?constituent rdfs:label ?label }
}

