  ?specimen a matsci:Specimen .
  ?specimen cco:ont00001904 ?quantity .
  { ?quantity a matsci:Mass } UNION { ?quantity a matsci:Volume }
  OPTIONAL { ?quantity cco:ont00001769 ?value }
  OPTIONAL { ?quantity rdfs:label ?label }
