PREFIX matsci: <https://cwrusdle.bitbucket.io/matsci/>
PREFIX cco: <https://www.commoncoreontologies.org/>
PREFIX obo: <http://purl.obolibrary.org/obo/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
SELECT ?sample1 ?sample2 ?composition ?process1 ?process2
WHERE {
  ?sample1 a matsci:MaterialSample ;
           cco:ont00001879 ?composition .
  ?sample2 a matsci:MaterialSample ;
           cco:ont00001879 ?composition .
  ?process1 obo:BFO_0000057 ?sample1 ;
            a matsci:ManufacturingProcess .
  ?process2 obo:BFO_0000057 ?sample2 ;
            a matsci:ManufacturingProcess .
  FILTER(?sample1 != ?sample2 && STR(?process1) != STR(?process2))
}

